do $$
declare
  v_template_id uuid;
  v_next_version integer;
  v_field_count integer;
  v_schema jsonb := $schema$
{"schemaVersion":1,"formType":"new_worker_orientation","title":"New Worker Orientation","description":"New worker and trade orientation record.","sections":[{"id":"new_worker_orientation","title":"NEW WORKER ORIENTATION","description":"","settings":{"layout":{"width":"half"}},"fields":[{"id":"decimal_16814083828123740","label":"Orientation #","helperText":"","required":true,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"third"}},"type":"number"},{"id":"dropdown_16855523457666497","label":"Worker Name","helperText":"","required":true,"default":"worker_name","remember":false,"options":[],"settings":{"layout":{"width":"third"}},"type":"short_text"},{"id":"text_16855522678352901","label":"Telephone Number","helperText":"","required":true,"default":"worker_phone","remember":false,"options":[],"settings":{"layout":{"width":"third"}},"type":"short_text"},{"id":"text_16481663734139969","label":"Company and Sub-Trade","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"half"}},"type":"short_text"},{"id":"text_16869293089126986","label":"Occupation","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"half"}},"type":"short_text"},{"id":"text_16643952863816764","label":"Supervisor Name","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"half"}},"type":"short_text"},{"id":"decimal_16481673047348717","label":"Supervisor Telephone","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"half"}},"type":"number"},{"id":"label_17132992642562222","label":"Emergency Contact Information","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"full"},"instructionStyle":"heading"},"type":"instructions"},{"id":"text_16481673390952630","label":"Emergency Contact Name","helperText":"","required":true,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"third"}},"type":"short_text"},{"id":"text_16481673106338880","label":"Relationship","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"third"}},"type":"short_text"},{"id":"decimal_16481672478377791","label":"Phone","helperText":"","required":true,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"third"}},"type":"number"},{"id":"multiattachment_173168983414763","label":"Paper Orientation Images","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"half"},"mediaUpload":{"acceptedKinds":["image"]}},"type":"media_upload"},{"id":"label_17133011702147212","label":"Before and during your work on our site you must meet, and comply with, all company and WorkSafeBC requirements. Review and initial each section below. Ensure you understand and follow all company rules and OHS Regulations. The items with an * will have continual competency observations.","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"full"},"instructionStyle":"policy"},"type":"instructions"},{"id":"text_17134582002626935","label":"Muster Station","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"half"},"defaultValue":"Northeast corner of site @ Skyline Drive (green sign)"},"type":"short_text"}]},{"id":"1_site_safety_and_emergency_procedures","title":"1 - SITE SAFETY AND EMERGENCY PROCEDURES","description":"","settings":{"layout":{"width":"half"}},"fields":[{"id":"label_1713301383204106","label":"•\tAppia’s Health and Safety policy\n•\tLocation of First Aid facilities and our FA attendants\n•\tHow to report illness and injury without delay\n•\tEmergency procedures & muster station\n•\tAir horns and Fire extinguishers (Located on every level)\n•\tAccess and egress route clear of obstructions and hazards\n•\tDuty to report hazards, incidents, near misses & unsafe acts\n•\tAccident/Incident investigations and reporting procedures\n•\tHousekeeping: ensure work area is clean at end of day\n•\tWorking alone or in isolation\n•\tBullying, harassment, threats, and violence- how to report\n•\tTheft and vandalism\n•\tAlcohol, drugs & impairment\n•\tStress, Excessive workload, mentally fit for work\n•\tCommunicable disease program\n•\tDO NOT come to work if you are contagious or not fit to work\n•\tCell phone use\n•\tSmoking and vaping\n•\tControl Zones, caution tape, danger tape and warning signs\n•\tWHMIS and storage of hazardous materials\n•\tSDS location, purpose, and key info on SDS and spill clean up","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"full"},"instructionStyle":"policy"},"type":"instructions"},{"id":"selection_17133031952269976","label":"Do you understand and agree to follow all company rules and OHS regulations regarding the topic reviewed in, Section 1: SITE SAFETY AND EMERGENCY PROCEDURES?","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"half"},"choiceDisplay":"radio","optionPreset":"yes_no"},"type":"dropdown"}]},{"id":"2_potential_hazards_and_responsibilities","title":"2 - POTENTIAL HAZARDS AND RESPONSIBILITIES","description":"","settings":{"layout":{"width":"half"}},"fields":[{"id":"label_0_1713302414064993","label":"•\t*Crane operations around site\n•\tOperating equipment with overlapping work zones\n•\t*Loading / Unloading Vehicles / Cranes / Rigging\n•\t*Working at heights\n•\t*Fall protection systems – guardrails, restraint, arrest, other\n•\t*Leading edge work (permit required)\n•\t*Dropped object prevention program\n•\t*Ladder use / work platforms\n•\tAccess / Egress\n•\t*Exposure to Silica Dust (ECP required)\n•\t*Hot Work (permit required)\n•\t*Confined Spaces (permit required)\n•\tElectrical Safety / Proximity to Powerlines\n•\t*Operating MEWPs (Scissor lift, etc.) & mobile equipment\n•\tWorking around mobile equipment\n•\tLifting Materials by Hand (MSI prevention)\n•\tRebar Protection and protruding objects\n•\tOperating equipment with overlapping work zones\n•\tFloor Openings\n•\tScaffolding/Swing stage - Work in high-risk situations\n•\tConcrete Formwork / Placing Concrete / Fly Tables\n•\tDefective tools and equipment\n•\tHierarchy of hazard controls","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"full"},"instructionStyle":"policy"},"type":"instructions"},{"id":"selection_1713303482073374","label":"Do you understand and agree to follow all company rules and OHS regulations regarding the topic reviewed in, Section 2: POTENTIAL HAZARDS AND RESPONSIBILITIES:","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"half"},"choiceDisplay":"radio","optionPreset":"yes_no"},"type":"dropdown"}]},{"id":"3_personal_protective_equipment","title":"3 - PERSONAL PROTECTIVE EQUIPMENT","description":"","settings":{"layout":{"width":"half"}},"fields":[{"id":"label_0_17133022482384353","label":"•\tAcceptable standards: CSA & ANSI\n•\tRequired PPE: Hard hat, safety boots & hi-visibility clothing\n•\tRequired Clothing: Long pants and shirt with sleeves\n•\tPPE fitting, Inspection & replacement\n•\tSpecialized PPE is provided by your employer\n•\tFollow manufacturer’s instructions, SWP and SJP\n•\tHearing Conservation Program\n•\tRespiratory Protection Program","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"full"},"instructionStyle":"policy"},"type":"instructions"},{"id":"selection_17133032804675939","label":"Do you understand and agree to follow all company rules and OHS regulations regarding the topic reviewed in, Section 3: PERSONAL PROTECTIVE EQUIPMENT","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"half"},"choiceDisplay":"radio","optionPreset":"yes_no"},"type":"dropdown"}]},{"id":"4_workplace_safety_rules_and_information","title":"4 - WORKPLACE SAFETY RULES AND INFORMATION","description":"","settings":{"layout":{"width":"half"}},"fields":[{"id":"label_0_1713302947892005","label":"•\tSite rules (and where to find them)\n•\tDisciplinary policy\n•\tReviewing safe job procedures and safe work practices\n•\tPublic interactions and radio etiquette\n•\tWorker Health and Safety Representative(s) and JOHS Committee\n•\tToolbox/safety meeting and safety committees\n•\tCompliance with OHS Program, basics of what is in it\n•\tLocation of WSBC regulations, OHS Program\n•\tTraffic (city and WSBC) and Noise Bylaw","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"full"},"instructionStyle":"policy"},"type":"instructions"},{"id":"selection_17133032096520","label":"Do you understand and agree to follow all company rules and OHS regulations regarding the topic reviewed in, Section 4: WORKPLACE SAFETY RULES AND INFORMATION","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"half"},"choiceDisplay":"radio","optionPreset":"yes_no"},"type":"dropdown"}]},{"id":"5_traffic_control","title":"5 – TRAFFIC CONTROL","description":"","settings":{"layout":{"width":"half"}},"fields":[{"id":"selection_17133031861943508","label":"Will you be doing traffic control on our site?","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"full"},"choiceDisplay":"radio","optionPreset":"yes_no"},"type":"dropdown"}]},{"id":"traffic_control","title":"TRAFFIC CONTROL","description":"","settings":{"layout":{"width":"half"}},"fields":[{"id":"label_1_17133051976249563","label":"•\tTraffic (city and WSBC) and Noise Bylaw\n•\tDaily Hazard Assessment is completed prior to work\n•\tSafe standing location & escape route identified/reviewed\n•\tTCP’s with appropriate PPE for the task","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"full"},"instructionStyle":"policy"},"type":"instructions"},{"id":"selection_2_1713305721483269","label":"Approved Traffic Control Layout is reviewed and understood?","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"half"},"choiceDisplay":"radio","optionPreset":"yes_no"},"type":"dropdown"},{"id":"selection_3_17133053839256226","label":"Do you understand and agree to follow all company rules and OHS regulations regarding the topic reviewed in, Section 5: TRAFFIC CONTROL","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"full"},"choiceDisplay":"radio","optionPreset":"yes_no"},"type":"dropdown"},{"id":"text_4_17133052079624950","label":"If more than 2 TCP's on duty, the coordinator is assigned. ","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"full"},"defaultValue":"Name:"},"type":"short_text"}]},{"id":"6_rights_and_responsibilities","title":"6 - RIGHTS AND RESPONSIBILITIES","description":"","settings":{"layout":{"width":"half"}},"fields":[{"id":"label_0_17133053223176800","label":"WORKER RIGHT TO:\n1. REFUSE unsafe work (that could affect the health and safety of you and others)\n2. KNOW workplace hazards and controls (as discussed in this orientation and while on the job)\n3. PARTICIPATE in health and safety activities (ex. Reporting unsafe acts or participating in the JOHS committee)\n4. BE SUPERVISED by a competent supervisor\n\nYOU ARE RESPONSIBLE TO:\n•\tWork safely and follow the Site Safety Rules\n•\tParticipate in, follow, and sign the Daily Hazard Assessment (FLRA/DHA/PSHA) as directed by your Supervisor\n•\tUse equipment you’re competent and authorized to use, as per Manufacturer’s Instructions\n•\tReport hazards – to your supervisor or site safety personnel without delay\n•\tClean up your mess as soon as possible AND before end of every shift\n•\tCorrect unsafe conditions and report all incidents and injuries – regardless of severity\n•\tControl and correct any hazard you create without delay\n•\tProvide proof of training BEFORE conducting work that requires training or certification\n•\tRespect the workplace and your fellow workers by not damaging any structure with graffiti or vandalism\n•\tRespect the workplace by using the functioning washroom facilities","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"full"},"instructionStyle":"policy"},"type":"instructions"},{"id":"selection_1_17133053671781066","label":"Do you understand and agree to follow all company rules and OHS regulations regarding the topic reviewed in, Section 6: RIGHTS AND RESPONSIBILITIES","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"half"},"choiceDisplay":"radio","optionPreset":"yes_no"},"type":"dropdown"}]},{"id":"7_training_and_certifications","title":"7 - TRAINING AND CERTIFICATIONS","description":"","settings":{"layout":{"width":"half"}},"fields":[{"id":"label_17133051935592110","label":"Do you have the following training or certifications:","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"full"},"instructionStyle":"heading"},"type":"instructions"},{"id":"selection_16481681303824803","label":"WHMIS training (required by regulation)","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"half"},"choiceDisplay":"radio","optionPreset":"yes_no"},"type":"dropdown"},{"id":"selection_16481681547357835","label":"Respirator fit tests ","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"half"},"choiceDisplay":"radio","optionPreset":"yes_no"},"type":"dropdown"},{"id":"selection_16481682225327036","label":"Annual hearing tests ","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"half"},"choiceDisplay":"radio","optionPreset":"yes_no"},"type":"dropdown"},{"id":"selection_1648168794923367","label":"Fall protection training?","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"half"},"choiceDisplay":"checklist"},"type":"multi_select"},{"id":"selection_16481683889480248","label":"Confined space training?","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"half"},"choiceDisplay":"radio","optionPreset":"yes_no"},"type":"dropdown"},{"id":"selection_1648168346207928","label":"Mobile Equipment training?","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"half"},"choiceDisplay":"checklist"},"type":"multi_select"},{"id":"multiattachment_1713305568750769","label":"UPLOAD OR TAKE PHOTOS OF CERTIFICATIONS HERE (including certifications not listed above IF required for your position)","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"half"},"mediaUpload":{"acceptedKinds":["image","pdf","excel"]}},"type":"media_upload"}]},{"id":"8_medical_information_optional_kept_confidential_and_only_provided_to_ems_if_nee","title":"8 - MEDICAL INFORMATION (Optional) – kept confidential and only provided to EMS if needed","description":"","settings":{"layout":{"width":"half"}},"fields":[{"id":"selection_16481682339605391","label":"Do you suffer / have you ever suffered from any form of heart or lung condition? ","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"half"},"choiceDisplay":"radio","optionPreset":"yes_no"},"type":"dropdown"},{"id":"textarea_1648168428921635","label":"Relevant details:","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"full"},"visibility":{"enabled":true,"sourceFieldId":"selection_16481682339605391","operator":"equals","value":"Yes"}},"type":"long_text"},{"id":"selection_16481683515022061","label":"Do you have any allergies to food or drugs? ","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"half"},"choiceDisplay":"radio","optionPreset":"yes_no"},"type":"dropdown"},{"id":"textarea_17133063084686767","label":"Relevant details:","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"full"},"visibility":{"enabled":true,"sourceFieldId":"selection_16481683515022061","operator":"equals","value":"Yes"}},"type":"long_text"},{"id":"selection_1648168623348657","label":"Do you suffer / have you ever suffered any chronic condition that could affect First Aid?","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"half"},"choiceDisplay":"radio","optionPreset":"yes_no"},"type":"dropdown"},{"id":"textarea_17133062840252164","label":"Relevant details:","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"full"},"visibility":{"enabled":true,"sourceFieldId":"selection_1648168623348657","operator":"equals","value":"Yes"}},"type":"long_text"},{"id":"selection_16481681212562529","label":"Are you currently being prescribed any medication (please list)?","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"half"},"choiceDisplay":"radio","optionPreset":"yes_no"},"type":"dropdown"},{"id":"textarea_17133062613575570","label":"Relevant details:","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"full"},"visibility":{"enabled":true,"sourceFieldId":"selection_16481681212562529","operator":"equals","value":"Yes"}},"type":"long_text"}]},{"id":"trade_orientation_confirmation","title":"Trade Orientation Confirmation","description":"","settings":{"layout":{"width":"half"}},"fields":[{"id":"selection_16481673054887164","label":"Are you less than 25 years old or less than one year of experience in construction?","helperText":"","required":false,"default":"","remember":false,"options":["Yes – stay after this orientation for additional info ","No"],"settings":{"layout":{"width":"half"},"choiceDisplay":"radio","optionPreset":""},"type":"dropdown"},{"id":"selection_17132991520838001","label":"Have you received a New or Young Worker Orientation or training by your Employer?","helperText":"","required":false,"default":"","remember":false,"options":["Yes","No"],"settings":{"layout":{"width":"half"},"choiceDisplay":"radio","optionPreset":"yes_no"},"type":"dropdown"},{"id":"text_17132993466359668","label":"Date of orientation by employer","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"third"},"visibility":{"enabled":true,"sourceFieldId":"selection_17132991520838001","operator":"equals","value":"Yes"}},"type":"short_text"},{"id":"text_1713299794274803","label":"No","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"third"},"visibility":{"enabled":true,"sourceFieldId":"selection_17132991520838001","operator":"equals","value":"No"},"defaultValue":"My Foreman/Supervisor will provide one before I begin work"},"type":"short_text"},{"id":"signature_1713300719466801","label":"Supervisor's acknowledgement: (To be completed by supervisor)","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"third"},"visibility":{"enabled":true,"sourceFieldId":"selection_17132991520838001","operator":"equals","value":"No"}},"type":"signature"}]},{"id":"9_worker_acknowledgment","title":"9 - WORKER ACKNOWLEDGMENT","description":"","settings":{"layout":{"width":"half"}},"fields":[{"id":"label_17133063749020514","label":"I acknowledge that I will follow the above information. I understand my responsibilities for my health and safety on site. I also agree to participating in my Employer’s Injury Management/Return to Work Program, and any other Health and Safety activities.","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"full"},"instructionStyle":"policy"},"type":"instructions"},{"id":"text_1731689882937498","label":"Worker's Name","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"half"}},"type":"short_text"},{"id":"signature_1681417603516284","label":"Worker Signature","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"half"}},"type":"signature"},{"id":"toggle_16481692524602738","label":"ORIENTATOR TO COMPLETE: I have reviewed the above workers information and it is complete.","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"full"}},"type":"toggle"},{"id":"text_1687185274712497","label":"Orientator's provider","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"half"}},"type":"short_text"},{"id":"signature_16481681013354839","label":"Orientator's Signature","helperText":"","required":false,"default":"","remember":false,"options":[],"settings":{"layout":{"width":"half"}},"type":"signature"},{"id":"text_16855523210890858","label":"Worker's name (hidden)","helperText":"","required":false,"default":"worker_name","remember":false,"options":[],"settings":{"layout":{"width":"half"},"hidden":true},"type":"short_text"}]}]}
$schema$::jsonb;
begin
  if jsonb_array_length(v_schema -> 'sections') <> 12 then
    raise exception 'New Worker Orientation template conversion failed: expected 12 sections, found %.',
      jsonb_array_length(v_schema -> 'sections');
  end if;

  select coalesce(sum(jsonb_array_length(section_item -> 'fields')), 0)
  into v_field_count
  from jsonb_array_elements(v_schema -> 'sections') as section_item;

  if v_field_count <> 57 then
    raise exception 'New Worker Orientation template conversion failed: expected 57 fields, found %.', v_field_count;
  end if;

  select id
  into v_template_id
  from public.form_templates
  where form_type = 'new_worker_orientation';

  if v_template_id is null then
    insert into public.form_templates (
      form_type,
      label,
      description,
      renderer_type,
      active,
      worker_visible,
      display_order
    )
    values (
      'new_worker_orientation',
      'New Worker Orientation',
      'New worker and trade orientation record.',
      'template',
      true,
      false,
      40
    )
    returning id into v_template_id;
  else
    update public.form_templates
    set
      label = 'New Worker Orientation',
      description = 'New worker and trade orientation record.',
      renderer_type = 'template',
      active = true,
      worker_visible = false,
      display_order = 40,
      archived_at = null,
      updated_at = now()
    where id = v_template_id;
  end if;

  select coalesce(max(version_number), 0) + 1
  into v_next_version
  from public.form_template_versions
  where template_id = v_template_id;

  update public.form_template_versions
  set
    status = 'archived',
    notes = coalesce(nullif(notes, ''), 'Draft archived while refreshing New Worker Orientation template.'),
    updated_at = now()
  where template_id = v_template_id
    and status = 'draft';

  insert into public.form_template_versions (
    template_id,
    form_type,
    version_number,
    status,
    schema,
    notes,
    published_at,
    created_at,
    updated_at
  )
  values (
    v_template_id,
    'new_worker_orientation',
    v_next_version,
    'draft',
    v_schema,
    'New Worker Orientation legacy form recreated as a V3 editable template.',
    null,
    now(),
    now()
  );
end $$;
